const fs = require\('fs'\);
const path = require\('path'\);
const https = require\('https'\);
const http = require\('http'\);

const BIN_DIR = path.join\(__dirname, 'bin'\);
fs.mkdirSync\(BIN_DIR, { recursive: true }\);

const url = 'https://github.com/ggerganov/whisper.cpp/releases/download/v1.7.4/whisper-v1.7.4-bin-x64.zip';
const dest = path.join\(BIN_DIR, 'whisper.zip'\);

function download\(url, dest\) {
  return new Promise\(\(resolve, reject\) => {
    const file = fs.createWriteStream\(dest\);
    const doReq = \(u\) => {
      const client = u.startsWith\('https'\) ? https : http;
      client.get\(u, {headers:{'User-Agent':'OSS'}}, \(res\) => {
        if \(res.statusCode >= 300 && res.statusCode < 400 && res.headers.location\) {
          file.close\(\); try{fs.unlinkSync\(dest\)}catch{}
          doReq\(res.headers.location\); return;
        }
        if \(res.statusCode !== 200\) { reject\(new Error\('HTTP '+res.statusCode\)\); return; }
        res.pipe\(file\);
        file.on\('finish', \(\) => { file.close\(\); resolve\(\); }\);
      }\).on\('error', reject\);
    };
    doReq\(url\);
  }\);
}

download\(url, dest\).then\(\(\) => {
  console.log\('Downloaded whisper binary zip'\);
}\).catch\(e => console.error\(e\)\);
